import{c as e,Q as r,j as o,m as d}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse(`{"title":"Skill Authoring Patterns from Anthropic's Best Practices","description":"","frontmatter":{"url":"https://generativeprogrammer.com/p/skill-authoring-patterns-from-anthropics","title":"Skill Authoring Patterns from Anthropic's Best Practices","date":"2026-04-20T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/scored/2026-04-20-skill-authoring-patterns.md","filePath":"research/ai-articles/scored/2026-04-20-skill-authoring-patterns.md","lastUpdated":1779796674000}`),a={name:"research/ai-articles/scored/2026-04-20-skill-authoring-patterns.md"};function l(s,t,n,i,c,h){return r(),o("div",null,[...t[0]||(t[0]=[d('<h1 id="skill-authoring-patterns-from-anthropic-s-best-practices" tabindex="-1">Skill Authoring Patterns from Anthropic&#39;s Best Practices <a class="header-anchor" href="#skill-authoring-patterns-from-anthropic-s-best-practices" aria-label="Permalink to &quot;Skill Authoring Patterns from Anthropic&#39;s Best Practices&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://generativeprogrammer.com/p/skill-authoring-patterns-from-anthropics" target="_blank" rel="noreferrer">https://generativeprogrammer.com/p/skill-authoring-patterns-from-anthropics</a><br><strong>作者</strong>：Generative Programmer<br><strong>日期</strong>：2026-04-19<br><strong>收錄日期</strong>：2026-04-20<br><strong>原始資料</strong>：Anthropic 官方 <a href="https://platform.claude.com/docs/en/agents-and-tools/agent-skills/best-practices" target="_blank" rel="noreferrer">Skill authoring best practices</a>、<a href="https://github.com/anthropics/skills/blob/main/skills/skill-creator/SKILL.md" target="_blank" rel="noreferrer">skill-creator SKILL.md</a>、<a href="https://resources.anthropic.com/hubfs/The-Complete-Guide-to-Building-Skill-for-Claude.pdf" target="_blank" rel="noreferrer">33-page Complete Guide</a></p><hr><h2 id="文章概覽" tabindex="-1">文章概覽 <a class="header-anchor" href="#文章概覽" aria-label="Permalink to &quot;文章概覽&quot;">​</a></h2><p>14 個 Skill 設計模式，5 大類別，每個模式包含：問題描述、解法、適用時機、取捨。 這是對 Anthropic 官方 Skill 設計最佳實踐的系統化整理。</p><hr><h2 id="_14-個模式速查" tabindex="-1">14 個模式速查 <a class="header-anchor" href="#_14-個模式速查" aria-label="Permalink to &quot;14 個模式速查&quot;">​</a></h2><h3 id="類別-a-discovery-selection-技能能否被選中" tabindex="-1">類別 A：Discovery &amp; Selection（技能能否被選中） <a class="header-anchor" href="#類別-a-discovery-selection-技能能否被選中" aria-label="Permalink to &quot;類別 A：Discovery &amp; Selection（技能能否被選中）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>模式</th><th>核心問題</th><th>解法</th></tr></thead><tbody><tr><td>1</td><td><strong>Activation Metadata</strong></td><td>description 太模糊導致 Claude 選錯或不選</td><td>description 要「主動觸發」：寫明什麼情境必用此 Skill，用第三人稱，略帶 pushy</td></tr><tr><td>2</td><td><strong>Exclusion Clause</strong></td><td>邊界模糊導致 Skill 在不適合時觸發</td><td>description 結尾加明確排除條件：&quot;Do NOT use for blog articles, newsletters, emails&quot;</td></tr></tbody></table><blockquote><p><strong>重要數字</strong>：description + when_to_use 總 token 上限 <strong>1,536 字元</strong>（Claude Code）；每句話都是競爭預算。</p></blockquote><h3 id="類別-b-context-economy-節省-context-window" tabindex="-1">類別 B：Context Economy（節省 context window） <a class="header-anchor" href="#類別-b-context-economy-節省-context-window" aria-label="Permalink to &quot;類別 B：Context Economy（節省 context window）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>模式</th><th>核心問題</th><th>解法</th></tr></thead><tbody><tr><td>3</td><td><strong>Context Budget</strong></td><td>Skill 重複解釋 Claude 已知的事</td><td>每段落都要「justify token cost」；移除廢話；統一術語（選一個詞，不用同義詞）</td></tr><tr><td>4</td><td><strong>Progressive Disclosure</strong></td><td>SKILL.md 800 行全部載入，但大多數呼叫不需要</td><td>SKILL.md 控制在 <strong>500 行以內</strong>，只做 TOC；細節放 FORMS.md / REFERENCE.md 等子檔，按需讀取</td></tr></tbody></table><blockquote><p><strong>500 行閾值</strong>：超過就應該用 Progressive Disclosure 拆分。子檔要加 TOC（長檔案截斷時 Claude 只能看到前面）。</p></blockquote><h3 id="類別-c-instruction-calibration-指令精確度" tabindex="-1">類別 C：Instruction Calibration（指令精確度） <a class="header-anchor" href="#類別-c-instruction-calibration-指令精確度" aria-label="Permalink to &quot;類別 C：Instruction Calibration（指令精確度）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>模式</th><th>核心問題</th><th>解法</th></tr></thead><tbody><tr><td>5</td><td><strong>Control Tuning</strong></td><td>過度限制扼殺彈性；過度鬆散導致關鍵步驟出錯</td><td>依任務脆弱度調整自由度：低危 = 文字指令；中危 = pseudocode；高危（DB 遷移）= 精確腳本，不允許修改</td></tr><tr><td>6</td><td><strong>Explain-the-Why</strong></td><td>ALWAYS/NEVER/MUST 規則沒有 context，邊界情況失效</td><td>規則後面附上原因：「用 constructor injection，因為 field injection 讓 Spring mock 困難」</td></tr><tr><td>7</td><td><strong>Template Scaffold</strong></td><td>每次呼叫輸出結構不一致</td><td>SKILL.md 中放有 placeholder 的模板；嚴格（機器解析）或彈性（人閱讀）兩種等級</td></tr><tr><td>8</td><td><strong>In-Skill Examples</strong></td><td>結構對但風格不對（commit msg 格式正確但語氣不對）</td><td>放 2-3 個 Input/Output 範例對；Templates 定骨架，Examples 校正風格</td></tr><tr><td>9</td><td><strong>Known Gotchas</strong></td><td>只有 happy path，遇到真實邊界情況 Claude 自行亂猜</td><td>加獨立 Gotchas section：「Scanned PDF 會靜默回傳 []，先 check page type」</td></tr></tbody></table><blockquote><p><strong>Gotchas section</strong> 被稱為「成熟 Skill 最有價值的內容」。</p></blockquote><h3 id="類別-d-workflow-control-多步驟流程控制" tabindex="-1">類別 D：Workflow Control（多步驟流程控制） <a class="header-anchor" href="#類別-d-workflow-control-多步驟流程控制" aria-label="Permalink to &quot;類別 D：Workflow Control（多步驟流程控制）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>模式</th><th>核心問題</th><th>解法</th></tr></thead><tbody><tr><td>10</td><td><strong>Execution Checklist</strong></td><td>長流程 Claude 跳過驗證步驟或提前宣告完成</td><td>在 Skill 中提供可貼入對話的 checklist；未勾選的步驟對用戶可見</td></tr><tr><td>11</td><td><strong>Self-Correcting Loop</strong></td><td>單次 forward pass 輸出有錯，沒有驗證機制</td><td>明確指示：產出 → 跑 validator → 失敗就修 → 直到通過；必須設 retry 上限防無限迴圈</td></tr><tr><td>12</td><td><strong>Plan-Validate-Execute</strong></td><td>批量/破壞性操作直接執行，錯誤已落地才發現</td><td>先產出 JSON plan → 腳本驗證 plan → <strong>通過才執行</strong>；與 Self-Correcting Loop 的差異：Plan 在副作用前驗證</td></tr></tbody></table><h3 id="類別-e-executable-code-腳本化" tabindex="-1">類別 E：Executable Code（腳本化） <a class="header-anchor" href="#類別-e-executable-code-腳本化" aria-label="Permalink to &quot;類別 E：Executable Code（腳本化）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>模式</th><th>核心問題</th><th>解法</th></tr></thead><tbody><tr><td>13</td><td><strong>Utility Bundle</strong></td><td>每次呼叫重新生成同樣的腳本，浪費 token</td><td>把重複邏輯寫成 <code>scripts/</code> 下的腳本；Claude 呼叫 bash 執行，只有輸出進 context</td></tr><tr><td>14</td><td><strong>Autonomy Calibration</strong></td><td>預設工具集過寬（有 Write 的 security-audit Skill 是安全風險）</td><td>YAML frontmatter 宣告 <code>allowed-tools</code>：security-audit 只給 Read/Grep/Glob；deploy 只給 Bash（窄 matcher）</td></tr></tbody></table><hr><h2 id="對-cc-workspace-現有-skills-的差距分析" tabindex="-1">對 cc-workspace 現有 Skills 的差距分析 <a class="header-anchor" href="#對-cc-workspace-現有-skills-的差距分析" aria-label="Permalink to &quot;對 cc-workspace 現有 Skills 的差距分析&quot;">​</a></h2><h3 id="立即可改善的問題-基於現有-claude-skills" tabindex="-1">立即可改善的問題（基於現有 <code>.claude/skills/</code>） <a class="header-anchor" href="#立即可改善的問題-基於現有-claude-skills" aria-label="Permalink to &quot;立即可改善的問題（基於現有 `.claude/skills/`）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模式</th><th>現況</th><th>建議</th></tr></thead><tbody><tr><td><strong>Exclusion Clause</strong></td><td>多數 Skill description 只有正向觸發，缺乏排除條件</td><td>在 <code>bugfix</code>、<code>web-fetch</code>、<code>deep-review</code> 等 description 加 &quot;Do NOT use for...&quot;</td></tr><tr><td><strong>Known Gotchas</strong></td><td>幾乎所有 Skill 都沒有 Gotchas section</td><td>從 <code>web-fetch</code> 開始補（已知：Next.js SPA、Cloudflare 防護等）</td></tr><tr><td><strong>Progressive Disclosure</strong></td><td><code>gh-fetch</code> 已達 200+ 行，內聯太多細節</td><td>考慮把 curl 範例移到 <code>scripts/</code> 子目錄</td></tr><tr><td><strong>Autonomy Calibration</strong></td><td>所有 Skill 都未設定 <code>allowed-tools</code></td><td>security-reviewer、deep-review 優先加 Read/Grep/Glob 限制</td></tr><tr><td><strong>Explain-the-Why</strong></td><td><code>bugfix</code> Skill 已有此模式（GEPA 背後的原因），其他 Skill 多為命令式</td><td>在 <code>web-fetch</code> fallback 步驟後加解釋（為何 WebFetch 對 Next.js 失效）</td></tr></tbody></table><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>9/10</td><td>直接對應 20+ 個 workspace Skills，每個模式都有具體改善機會</td></tr><tr><td>B. 創新性</td><td>9/10</td><td>Progressive Disclosure、Plan-Validate-Execute、Known Gotchas、Autonomy Calibration 都是 workspace 現有 Skills 未實作的模式</td></tr><tr><td>C. 證據品質</td><td>8/10</td><td>基於 Anthropic 官方文件，非實驗數據，但有具體來源可追溯</td></tr><tr><td>D. 技術深度</td><td>8/10</td><td>每個模式有問題 + 解法 + 適用時機 + 取捨；500 行/1536 字元等具體數字</td></tr><tr><td>E. 泛化性</td><td>9/10</td><td>適用於所有 <code>.claude/skills/</code> 下的 Skill，不分功能類別</td></tr><tr><td><strong>加權總分</strong></td><td><strong>8.65/10</strong></td><td></td></tr></tbody></table><p><strong>整合決策</strong>：Rule（新增 <code>.claude/rules/skill-authoring.md</code>）<br><strong>理由</strong>：這是「設計/更新 Skill 時」的參考規則，不是單一任務的執行 Skill。最適合做成按需載入的 Rule，在任何建立或修改 Skill 的場景自動提供指引。<br><strong>整合位置</strong>：<code>.claude/rules/skill-authoring.md</code><br><strong>整合狀態</strong>：✅ 已完成</p><p><strong>後續建議（可選）</strong>：</p><ul><li>委派 <code>implementer</code> 對 <code>deep-review</code>、<code>web-fetch</code>、<code>bugfix</code> 三個 Skill 加入 Exclusion Clause + Known Gotchas</li><li>對 <code>deep-review</code> 加入 <code>allowed-tools: Read, Grep, Glob</code> 的 Autonomy Calibration</li></ul>',30)])])}const p=e(a,[["render",l]]);export{g as __pageData,p as default};
